// ---------------------------------------------------------------------------
// small utilities: math helpers and a deterministic seeded RNG
// ---------------------------------------------------------------------------

var __seed = 987654321;

double frand() {
  __seed = (__seed * 1103515245 + 12345) % 2147483648;
  return __seed / 2147483648.0;
}

double frandRange(double lo, double hi) => lo + (hi - lo) * frand();

double lerp(double a, double b, double t) => a + (b - a) * t;

double clampf(double v, double lo, double hi) {
  if (v < lo) {
    return lo;
  }
  if (v > hi) {
    return hi;
  }
  return v;
}

double vlen3(double x, double y, double z) => sqrt(x * x + y * y + z * z);

// Shortest-path angle approach (keeps model turns smooth across the Â±PI seam).
double approachAngle(double cur, double target, double maxStep) {
  var d = target - cur;
  while (d > PI) {
    d = d - 2.0 * PI;
  }
  while (d < 0.0 - PI) {
    d = d + 2.0 * PI;
  }
  if (d > maxStep) {
    d = maxStep;
  }
  if (d < 0.0 - maxStep) {
    d = 0.0 - maxStep;
  }
  return cur + d;
}

