void cacheConstants() {
  // One-time reflection reads. Under the mock every value is 0 â€” all uses are
  // written so that is harmless.
  var names = [
    "KEY_W", "KEY_A", "KEY_S", "KEY_D", "KEY_SPACE", "KEY_SHIFT", "KEY_R",
    "KEY_Q", "KEY_1", "KEY_2", "KEY_ESCAPE",
    "MOUSE_BUTTON_LEFT", "MOUSE_BUTTON_RIGHT",
    "MOUSE_BUTTON_WHEEL_UP", "MOUSE_BUTTON_WHEEL_DOWN",
  ];
  for (var n in names) {
    C[n] = GD.constant(n);
  }
  C["MOUSE_CAPTURED"] = GD.constant("Input.MOUSE_MODE_CAPTURED");
  C["MOUSE_VISIBLE"] = GD.constant("Input.MOUSE_MODE_VISIBLE");
  C["BILLBOARD"] = GD.constant("BaseMaterial3D.BILLBOARD_ENABLED");
  C["SHADED_OFF"] = GD.constant("BaseMaterial3D.SHADING_MODE_UNSHADED");
  C["TRANSPARENCY_ALPHA"] = GD.constant("BaseMaterial3D.TRANSPARENCY_ALPHA");
  C["LOOP_LINEAR"] = GD.constant("Animation.LOOP_LINEAR");
  C["BG_SKY"] = GD.constant("Environment.BG_SKY");
  C["AMBIENT_SKY"] = GD.constant("Environment.AMBIENT_SOURCE_SKY");
  C["TONE_ACES"] = GD.constant("Environment.TONE_MAPPER_ACES");
  C["FOCUS_OUT"] = GD.constant("Node.NOTIFICATION_APPLICATION_FOCUS_OUT");
  C["PRESET_FULL"] = 15;
  C["PRESET_CENTER"] = 8;
  C["MOUSE_IGNORE"] = 2;
}

// Register one GLB if it is importable in this runtime; otherwise the entry
// stays absent and builders fall back to procedural primitives.
void registerAsset(String key, String path) {
  var loader = GD.resourceLoader();
  var okv = loader.call("exists", [path]);
  if (okv == true) {
    var res = GD.load(path);
    if (res is GObj) {
      assets[key] = res;
      assetsAvailable = true;
    }
  }
}

void loadAssets() {
  var b = "res://assets/tps/";
