// Build one AudioStreamWAV from an embedded base64 PCM constant.
dynamic makeStream(String b64, int format, int rate, bool loop) {
  var s = GD.create("AudioStreamWAV");
  s.set("data", Packed.bytesBase64(b64));
  s.set("format", GInt(format));
  s.set("mix_rate", GInt(rate));
  s.set("stereo", false);
  if (loop) {
    s.set("loop_mode", GInt(1));
    // loop over the whole buffer; loop_end is in samples
    var bytesPerSample = format == 1 ? 2 : 1;
    s.set("loop_end", GInt((b64.length * 3) ~/ (4 * bytesPerSample)));
  }
  return s;
}

void buildAudio() {
  sfxStreams["shot"] = makeStream(sfx_shot, sfxMeta_shot[0], sfxMeta_shot[1], false);
  sfxStreams["heavy"] = makeStream(sfx_heavy, sfxMeta_heavy[0], sfxMeta_heavy[1], false);
  sfxStreams["hit"] = makeStream(sfx_hit, sfxMeta_hit[0], sfxMeta_hit[1], false);
  sfxStreams["hurt"] = makeStream(sfx_hurt, sfxMeta_hurt[0], sfxMeta_hurt[1], false);
  sfxStreams["reload"] = makeStream(sfx_reload, sfxMeta_reload[0], sfxMeta_reload[1], false);
  sfxStreams["death"] = makeStream(sfx_death, sfxMeta_death[0], sfxMeta_death[1], false);
  sfxStreams["pickup"] = makeStream(sfx_pickup, sfxMeta_pickup[0], sfxMeta_pickup[1], false);
  sfxStreams["empty"] = makeStream(sfx_empty, sfxMeta_empty[0], sfxMeta_empty[1], false);
  sfxStreams["horn"] = makeStream(sfx_horn, sfxMeta_horn[0], sfxMeta_horn[1], false);

  var i = 0;
  while (i < 6) {
    var p = GD.create("AudioStreamPlayer");
    p.set("volume_db", GFloat(-6.0));
    GD.mount(p);
    sfxPlayers.add(p);
    i = i + 1;
  }

  ambiencePlayer = GD.create("AudioStreamPlayer");
  ambiencePlayer.set("stream",
      makeStream(sfx_ambience, sfxMeta_ambience[0], sfxMeta_ambience[1], true));
  ambiencePlayer.set("volume_db", GFloat(-14.0));
  ambiencePlayer.set("autoplay", true);
  GD.mount(ambiencePlayer);
  ambiencePlayer.call("play", []);
}

void playSfx(String name, double volumeDb, double pitchLo, double pitchHi) {
  var s = sfxStreams[name];
  if (!(s is GObj)) {
    return;
  }
  if (sfxPlayers.length == 0) {
    return;
  }
  var p = sfxPlayers[sfxNext % sfxPlayers.length];
  sfxNext = sfxNext + 1;
  p.set("stream", s);
  p.set("volume_db", GFloat(volumeDb));
  p.set("pitch_scale", GFloat(frandRange(pitchLo, pitchHi)));
  p.call("play", []);
}

