void buildEnvironment() {
  GD.beginBatch();
  var worldEnv = GD.create("WorldEnvironment");
  var env = GD.create("Environment");
  var sky = GD.create("Sky");
  var skyMat = GD.create("ProceduralSkyMaterial");
  GD.endBatch();

  // late-afternoon downtown: warm horizon, deep blue zenith, soft haze
  skyMat.set("sky_top_color", Color(0.18, 0.32, 0.52, 1.0));
  skyMat.set("sky_horizon_color", Color(0.86, 0.62, 0.42, 1.0));
  skyMat.set("ground_bottom_color", Color(0.10, 0.10, 0.12, 1.0));
  skyMat.set("ground_horizon_color", Color(0.62, 0.48, 0.40, 1.0));
  skyMat.set("sun_angle_max", GFloat(20.0));
  sky.set("sky_material", skyMat);

  env.set("background_mode", C["BG_SKY"]);
  env.set("sky", sky);
  env.set("ambient_light_source", C["AMBIENT_SKY"]);
  env.set("ambient_light_energy", GFloat(1.1));
  env.set("tonemap_mode", C["TONE_ACES"]);
  env.set("glow_enabled", true);
  env.set("glow_bloom", GFloat(0.15));
  env.set("fog_enabled", true);
  env.set("fog_light_color", Color(0.75, 0.6, 0.5, 1.0));
  env.set("fog_density", GFloat(0.004));
  worldEnv.set("environment", env);
  GD.mount(worldEnv);

  var sun = GD.create("DirectionalLight3D");
  sun.set("rotation", Vector3(-0.62, 2.35, 0.0));
  sun.set("light_color", Color(1.0, 0.87, 0.7, 1.0));
  sun.set("light_energy", GFloat(1.35));
  sun.set("shadow_enabled", true);
  GD.mount(sun);
}

double cellWorld(int c) => (c - (GRID - 1) / 2.0) * CELL;

// Instantiate a registered scene (returns null when the asset is absent).
dynamic spawnScene(String key) {
  var res = assets[key];
  if (!(res is GObj)) {
    return null;
  }
  var inst = res.call("instantiate", []);
  if (inst is GObj) {
    return inst;
  }
  return null;
}

// Static collision box helper: an invisible StaticBody3D of size (w,h,d)
// whose base sits at ground level, centred at (x, z), yaw-rotated.
void addStaticBox(double x, double z, double w, double h, double d, double yawRot) {
  GD.beginBatch();
  var body = GD.create("StaticBody3D");
  var col = GD.create("CollisionShape3D");
  var box = GD.create("BoxShape3D");
  box.set("size", Vector3(w, h, d));
  col.set("shape", box);
  col.set("position", Vector3(0.0, h / 2.0, 0.0));
  body.call("add_child", [col]);
  body.set("position", Vector3(x, ROAD_Y, z));
  body.set("rotation", Vector3(0.0, yawRot, 0.0));
  body.set("collision_layer", GInt(1));
  body.set("collision_mask", GInt(0));
  GD.mount(body);
  GD.endBatch();
}

// Place a kit model (or a fallback box of the given tint) with collision.
void placeStructure(String key, double x, double z, double yawRot, double scale,
    double w, double h, double d, Color fallbackTint) {
  var inst = spawnScene(key);
  if (inst is GObj) {
    GD.beginBatch();
    inst.set("position", Vector3(x, ROAD_Y, z));
    inst.set("rotation", Vector3(0.0, yawRot, 0.0));
    inst.set("scale", Vector3(scale, scale, scale));
    GD.mount(inst);
    GD.endBatch();
  } else {
    // procedural fallback: a simple tinted box of the same footprint
    GD.beginBatch();
    var m = GD.create("MeshInstance3D");
    var box = GD.create("BoxMesh");
    var mat = GD.create("StandardMaterial3D");
    box.set("size", Vector3(w * scale, h * scale, d * scale));
    mat.set("albedo_color", fallbackTint);
    mat.set("roughness", GFloat(0.8));
    box.set("material", mat);
    m.set("mesh", box);
    m.set("position", Vector3(x, ROAD_Y + h * scale / 2.0, z));
    m.set("rotation", Vector3(0.0, yawRot, 0.0));
    GD.mount(m);
    GD.endBatch();
  }
  addStaticBox(x, z, w * scale, h * scale, d * scale, yawRot);
  buildingCount = buildingCount + 1;
}

// Purely cosmetic scenery (road tiles, pavement, lights) â€” no collider.
void placeProp(String key, double x, double y, double z, double yawRot, double scale) {
  var inst = spawnScene(key);
  if (!(inst is GObj)) {
    return;
  }
  GD.beginBatch();
  inst.set("position", Vector3(x, y, z));
  inst.set("rotation", Vector3(0.0, yawRot, 0.0));
  inst.set("scale", Vector3(scale, scale, scale));
  GD.mount(inst);
  GD.endBatch();
}

void buildGround() {
  // one big asphalt slab + the walkable collider under the whole map
  GD.beginBatch();
  var m = GD.create("MeshInstance3D");
  var plane = GD.create("PlaneMesh");
  var mat = GD.create("StandardMaterial3D");
  plane.set("size", Vector2(GRID * CELL + 60.0, GRID * CELL + 60.0));
  mat.set("albedo_color", Color(0.13, 0.13, 0.15, 1.0));
  mat.set("roughness", GFloat(0.95));
  plane.set("material", mat);
  m.set("mesh", plane);
  m.set("position", Vector3(0.0, 0.0, 0.0));
  GD.mount(m);

  var body = GD.create("StaticBody3D");
  var col = GD.create("CollisionShape3D");
  var box = GD.create("BoxShape3D");
  box.set("size", Vector3(GRID * CELL + 60.0, 1.0, GRID * CELL + 60.0));
  col.set("shape", box);
  col.set("position", Vector3(0.0, ROAD_Y - 0.5, 0.0));
  body.call("add_child", [col]);
  body.set("collision_layer", GInt(1));
  body.set("collision_mask", GInt(0));
  GD.mount(body);
  GD.endBatch();

  // invisible boundary walls so nobody leaves the combat zone
  var half = (GRID - 1) / 2.0 * CELL + CELL;
  addStaticBox(0.0, 0.0 - half, GRID * CELL + 20.0, 12.0, 2.0, 0.0);
  addStaticBox(0.0, half, GRID * CELL + 20.0, 12.0, 2.0, 0.0);
  addStaticBox(0.0 - half, 0.0, 2.0, 12.0, GRID * CELL + 20.0, 0.0);
  addStaticBox(half, 0.0, 2.0, 12.0, GRID * CELL + 20.0, 0.0);
}

void buildRoads() {
  var r = 0;
  while (r < GRID) {
    var c = 0;
    while (c < GRID) {
      var onRow = r % 4 == 0;
      var onCol = c % 4 == 0;
      var x = cellWorld(c);
      var z = cellWorld(r);
      if (onRow && onCol) {
        placeProp("crossroad", x, 0.0, z, 0.0, KIT_SCALE);
        spawnPoints.add([x, z]);
        // two street lights on opposite corners of each intersection
        if ((r + c) % 8 == 0) {
          placeProp("streetlight", x + 3.4, ROAD_Y, z + 3.4, PI * 0.75, KIT_SCALE);
          placeProp("streetlight", x - 3.4, ROAD_Y, z - 3.4, PI * 1.75, KIT_SCALE);
        }
      } else if (onRow) {
        // a road running along X: rotate the (Z-aligned) tile a quarter turn
        placeProp("road", x, 0.0, z, PI / 2.0, KIT_SCALE);
      } else if (onCol) {
        placeProp("road", x, 0.0, z, 0.0, KIT_SCALE);
      } else {
        placeProp("pavement", x, 0.0, z, 0.0, KIT_SCALE);
      }
      c = c + 1;
    }
    r = r + 1;
  }
}

void buildBlocks() {
  // catalog: key, footprint w, h, d (unit scale â€” multiplied by KIT_SCALE)
  var smallBuildings = [
    ["building-a", 0.88, 1.29, 0.94],
    ["building-b", 0.97, 1.29, 0.94],
    ["building-c", 0.88, 0.89, 1.09],
    ["building-d", 0.84, 1.29, 0.90],
    ["building-f", 0.84, 1.69, 1.03],
    ["building-g", 0.97, 1.69, 0.92],
    ["building-h", 0.88, 1.29, 1.01],
  ];
  var towers = [
    ["tower-a", 1.36, 2.88, 1.36],
    ["tower-b", 1.36, 4.48, 1.36],
    ["tower-e", 1.29, 4.08, 1.24],
  ];

  var bi = 0;
  while (bi < 4) {
    var bj = 0;
    while (bj < 4) {
      var s0r = bi * 4 + 1; // block's first cell (rows)
      var s0c = bj * 4 + 1;
      var cx = cellWorld(s0c + 1); // block centre
      var cz = cellWorld(s0r + 1);
      var inner = (bi == 1 || bi == 2) && (bj == 1 || bj == 2);
      var roll = frand();
      if (inner && roll < 0.75) {
        // downtown core: one skyscraper on the whole block
        var t = towers[floor(frand() * 3.0) % 3];
        placeStructure(t[0], cx, cz, floor(frand() * 4.0) * PI / 2.0,
            KIT_SCALE, t[1], t[2], t[3], Color(0.35, 0.38, 0.45, 1.0));
      } else if (roll < 0.2) {
        // a low mall building + parking
        placeStructure("mall", cx, cz, (frand() < 0.5 ? 0.0 : PI / 2.0),
            KIT_SCALE, 1.64, 0.89, 1.01, Color(0.45, 0.4, 0.35, 1.0));
      } else {
        // four mid-rises on the block corners, facing outward
        var corners = [[s0c, s0r, PI], [s0c + 2, s0r, PI],
            [s0c, s0r + 2, 0.0], [s0c + 2, s0r + 2, 0.0]];
        for (var corner in corners) {
          if (frand() < 0.85) {
            var m = smallBuildings[floor(frand() * 7.0) % 7];
            placeStructure(m[0], cellWorld(corner[0]), cellWorld(corner[1]),
                corner[2] + (frand() < 0.3 ? PI / 2.0 : 0.0), KIT_SCALE,
                m[1], m[2], m[3], Color(0.42, 0.4, 0.38, 1.0));
          }
        }
        // the block centre stays open â€” remember it as a pickup plaza
        plazaPoints.add([cx, cz]);
      }
      bj = bj + 1;
    }
    bi = bi + 1;
  }
}

void buildCars() {
  var models = ["car-sedan", "car-taxi", "car-police", "car-van", "car-suv",
      "car-delivery"];
  var n = 0;
  while (n < 14) {
    // park along a random road line, offset to the kerb
    var line = floor(frand() * 5.0) % 5; // which road (0,4,8,12,16)
    var along = frandRange(0.0 - 7.5, 7.5) * CELL;
    var kerb = frand() < 0.5 ? 2.9 : -2.9;
    var horizontal = frand() < 0.5;
    var x = horizontal ? along : cellWorld(line * 4) + kerb;
    var z = horizontal ? cellWorld(line * 4) + kerb : along;
    var rot = horizontal ? PI / 2.0 : 0.0;
    if (frand() < 0.5) {
      rot = rot + PI;
    }
    // keep intersections and the player spawn clear
    if (abs(x) + abs(z) > 6.0) {
      var m = models[floor(frand() * 6.0) % 6];
      var inst = spawnScene(m);
      if (inst is GObj) {
        GD.beginBatch();
        inst.set("position", Vector3(x, ROAD_Y, z));
        inst.set("rotation", Vector3(0.0, rot, 0.0));
        inst.set("scale", Vector3(CAR_SCALE, CAR_SCALE, CAR_SCALE));
        GD.mount(inst);
        GD.endBatch();
        addStaticBox(x, z, 1.5 * CAR_SCALE, 1.3 * CAR_SCALE, 2.8 * CAR_SCALE, rot);
      }
    }
    n = n + 1;
  }
}

void buildCity() {
  buildGround();
  buildRoads();
  buildBlocks();
  buildCars();
  worldRootBuilt = true;
  print("[tps] city built: " + buildingCount + " structures, " +
      spawnPoints.length + " intersections, " + plazaPoints.length + " plazas");
}

// ---------------------------------------------------------------------------
// characters: shared model rig helpers
// ---------------------------------------------------------------------------

// Instance a character scene under a yaw-holder, attach a weapon to the right
// hand, resolve the AnimationPlayer, and mark looping clips. Returns
// [holder, animPlayer(or null)]. Falls back to a capsule figure.
dynamic buildCharacter(String charKey, String gunKey, Color fallbackTint) {
  var holder = GD.create("Node3D");
  var inst = spawnScene(charKey);
  var ap = null;
  __lastArm = null;
  __lastGun = null;
  if (inst is GObj) {
    GD.beginBatch();
    inst.set("scale", Vector3(CHAR_SCALE, CHAR_SCALE, CHAR_SCALE));
    inst.set("rotation", Vector3(0.0, MODEL_YAW_FIX, 0.0));
    holder.call("add_child", [inst]);
    GD.endBatch();
    ap = inst.call("find_child", ["AnimationPlayer", true, false]);
    if (ap is GObj) {
      var loops = ["idle", "walk", "sprint", "holding-right"];
      for (var name in loops) {
        var anim = ap.call("get_animation", [name]);
        if (anim is GObj) {
          anim.call("set_loop_mode", [C["LOOP_LINEAR"]]);
        }
      }
    }
    var arm = inst.call("find_child", ["arm-right", true, false]);
    if (arm is GObj) {
      __lastArm = arm;
      var gun = spawnScene(gunKey);
      if (gun is GObj) {
        GD.beginBatch();
        // the arm node lives in character space (scaled 0.7 by the instance);
        // the blaster is ~0.9 units long â€” size it to the blocky hand
        gun.set("position", Vector3(0.0, -0.5, -0.3));
        gun.set("rotation", Vector3(0.0, PI, 0.0));
        gun.set("scale", Vector3(0.9, 0.9, 0.9));
        arm.call("add_child", [gun]);
        GD.endBatch();
        __lastGun = gun;
      }
    }
  } else {
    // fallback figure: tinted capsule + head cube + gun box
    GD.beginBatch();
    var bodyMesh = GD.create("MeshInstance3D");
    var capsule = GD.create("CapsuleMesh");
    var mat = GD.create("StandardMaterial3D");
    capsule.set("radius", GFloat(0.34));
    capsule.set("height", GFloat(1.5));
    mat.set("albedo_color", fallbackTint);
    capsule.set("material", mat);
    bodyMesh.set("mesh", capsule);
    bodyMesh.set("position", Vector3(0.0, 0.95, 0.0));
    holder.call("add_child", [bodyMesh]);
    var head = GD.create("MeshInstance3D");
    var headBox = GD.create("BoxMesh");
    headBox.set("size", Vector3(0.42, 0.42, 0.42));
    headBox.set("material", mat);
    head.set("mesh", headBox);
    head.set("position", Vector3(0.0, 1.85, 0.0));
    holder.call("add_child", [head]);
    var gunMesh = GD.create("MeshInstance3D");
    var gunBox = GD.create("BoxMesh");
    var gunMat = GD.create("StandardMaterial3D");
    gunBox.set("size", Vector3(0.1, 0.14, 0.7));
    gunMat.set("albedo_color", Color(0.15, 0.15, 0.17, 1.0));
    gunBox.set("material", gunMat);
    gunMesh.set("mesh", gunBox);
    gunMesh.set("position", Vector3(0.3, 1.3, -0.35));
    holder.call("add_child", [gunMesh]);
    GD.endBatch();
  }
  return [holder, ap];
}

// Change a character's animation only when the requested clip differs.
String driveAnim(ap, String current, String next) {
  if (current == next) {
    return current;
  }
  if (ap is GObj) {
    ap.call("play", [next, GFloat(0.18)]);
  }
  return next;
}

// ---------------------------------------------------------------------------
// player construction
// ---------------------------------------------------------------------------

void buildPlayer() {
  playerBody = GD.create("CharacterBody3D");
  GD.beginBatch();
  var col = GD.create("CollisionShape3D");
  var shape = GD.create("CapsuleShape3D");
  shape.set("radius", GFloat(0.38));
  shape.set("height", GFloat(1.8));
  col.set("shape", shape);
  col.set("position", Vector3(0.0, 0.95, 0.0));
  playerBody.call("add_child", [col]);
  playerBody.set("collision_layer", GInt(2));
  playerBody.set("collision_mask", GInt(5)); // world + enemies
  playerBody.set("position", Vector3(px, py, pz));
  GD.mount(playerBody);
  GD.endBatch();

  var rig = buildCharacter("char-player", "gun-rifle", Color(0.25, 0.55, 0.85, 1.0));
  playerModel = rig[0];
  playerAnim = rig[1];
  playerBody.call("add_child", [playerModel]);
  playerBody.call("set_meta", ["is_player", true]);
  playerAnimState = driveAnim(playerAnim, playerAnimState, "holding-right");

  // second weapon model on the same hand, hidden until selected
  playerArm = __lastArm;
  weaponNodes.add(__lastGun);
  var g2 = null;
  if (playerArm is GObj) {
    g2 = spawnScene("gun-heavy");
    if (g2 is GObj) {
      GD.beginBatch();
      g2.set("position", Vector3(0.0, -0.5, -0.3));
      g2.set("rotation", Vector3(0.0, PI, 0.0));
      g2.set("scale", Vector3(1.0, 1.0, 1.0));
      g2.set("visible", false);
      playerArm.call("add_child", [g2]);
      GD.endBatch();
    }
  }
  weaponNodes.add(g2);

  playerRid = playerBody.call("get_rid", []);

  // camera rig: follow node â†’ yaw â†’ pitch â†’ spring arm â†’ camera
  camRig = GD.create("Node3D");
  GD.beginBatch();
  camYawNode = GD.create("Node3D");
  camPitchNode = GD.create("Node3D");
  camSpring = GD.create("SpringArm3D");
  camera = GD.create("Camera3D");
  camRig.call("add_child", [camYawNode]);
  camYawNode.call("add_child", [camPitchNode]);
  camPitchNode.call("add_child", [camSpring]);
  camSpring.call("add_child", [camera]);
  camSpring.set("spring_length", GFloat(CAM_DIST));
  camSpring.set("collision_mask", GInt(1)); // clip against world only
  camSpring.set("margin", GFloat(0.25));
  camera.set("position", Vector3(0.5, 0.25, 0.0)); // over-the-shoulder offset
  camera.set("fov", GFloat(FOV_BASE));
  camRig.set("position", Vector3(px, py + EYE_HEIGHT, pz));
  GD.mount(camRig);
  GD.endBatch();
  camera.set("current", true);
  if (playerRid != null) {
    camSpring.call("add_excluded_object", [playerRid]);
  }

  muzzleLight = GD.create("OmniLight3D");
  GD.beginBatch();
  muzzleLight.set("light_color", Color(1.0, 0.75, 0.4, 1.0));
  muzzleLight.set("omni_range", GFloat(7.0));
  muzzleLight.set("light_energy", GFloat(0.0));
  GD.mount(muzzleLight);
  GD.endBatch();

  print("[tps] player ready");
}

void setupWeapons() {
  var rifle = Wpn("PULSE RIFLE", "gun-rifle", 30, 12.0, 9.0, true, 0.02, 1.4);
  rifle.mag = 30;
  rifle.reserve = 120;
  var heavy = Wpn("ARC CANNON", "gun-heavy", 6, 55.0, 1.6, false, 0.006, 2.0);
  heavy.mag = 6;
  heavy.reserve = 24;
  weapons.add(rifle);
  weapons.add(heavy);
  currentWeapon = 0;
}

// physics-space raycast plumbing (built lazily once the world exists)
void setupRaycast() {
  var vp = GD.host().call("get_viewport", []);
  if (!(vp is GObj)) {
    return;
  }
  var world = vp.call("find_world_3d", []);
  if (!(world is GObj)) {
    return;
  }
  var ss = world.call("get_direct_space_state", []);
  if (!(ss is GObj)) {
    return;
  }
  spaceState = ss;
  rayQuery = GD.create("PhysicsRayQueryParameters3D");
  rayReady = true;
}

// Cast a ray; returns the intersection map ({} / null â†’ no hit).
dynamic castRay(double fx, double fy, double fz, double tx, double ty,
    double tz, int mask, excludeRid) {
  if (!rayReady) {
    setupRaycast();
  }
  if (!rayReady) {
    return null;
  }
  GD.beginBatch();
  rayQuery.set("from", Vector3(fx, fy, fz));
  rayQuery.set("to", Vector3(tx, ty, tz));
  rayQuery.set("collision_mask", GInt(mask));
  if (excludeRid != null) {
    rayQuery.set("exclude", [excludeRid]);
  }
  spaceState.call("intersect_ray", [rayQuery]);
  var results = GD.endBatch();
  if (results is List) {
    if (results.length > 0) {
      var hit = results[results.length - 1];
      if (hit is Map) {
        return hit;
      }
    }
  }
  return null;
}

// ---------------------------------------------------------------------------
// effects pools (tracers, impact sparks, floating damage numbers)
// ---------------------------------------------------------------------------

void buildEffects() {
  var i = 0;
  while (i < 10) {
    var fx = Fx("tracer");
    GD.beginBatch();
    var m = GD.create("MeshInstance3D");
    var box = GD.create("BoxMesh");
    var mat = GD.create("StandardMaterial3D");
    box.set("size", Vector3(0.045, 0.045, 1.0));
    mat.set("albedo_color", Color(1.0, 0.85, 0.45, 1.0));
    mat.set("emission_enabled", true);
    mat.set("emission", Color(1.0, 0.8, 0.35, 1.0));
    mat.set("emission_energy_multiplier", GFloat(2.4));
    mat.set("shading_mode", C["SHADED_OFF"]);
    box.set("material", mat);
    m.set("mesh", box);
    m.set("visible", false);
    GD.mount(m);
    GD.endBatch();
    fx.node = m;
    tracers.add(fx);
    i = i + 1;
  }

  i = 0;
  while (i < 8) {
    var fx = Fx("impact");
    GD.beginBatch();
    var m = GD.create("MeshInstance3D");
    var sphere = GD.create("SphereMesh");
    var mat = GD.create("StandardMaterial3D");
    sphere.set("radius", GFloat(0.09));
    sphere.set("height", GFloat(0.18));
    mat.set("albedo_color", Color(1.0, 0.6, 0.25, 0.9));
    mat.set("emission_enabled", true);
    mat.set("emission", Color(1.0, 0.55, 0.2, 1.0));
    mat.set("emission_energy_multiplier", GFloat(3.0));
    mat.set("transparency", C["TRANSPARENCY_ALPHA"]);
    mat.set("shading_mode", C["SHADED_OFF"]);
    sphere.set("material", mat);
    m.set("mesh", sphere);
    m.set("visible", false);
    GD.mount(m);
    GD.endBatch();
    fx.node = m;
    fx.extra = mat;
    impacts.add(fx);
    i = i + 1;
  }

  i = 0;
  while (i < 6) {
    var fx = Fx("popup");
    GD.beginBatch();
    var l = GD.create("Label3D");
    l.set("billboard", C["BILLBOARD"]);
    l.set("no_depth_test", true);
    l.set("font_size", GInt(64));
    l.set("outline_size", GInt(14));
    l.set("pixel_size", GFloat(0.004));
    l.set("visible", false);
    GD.mount(l);
    GD.endBatch();
    fx.node = l;
    popups.add(fx);
    i = i + 1;
  }
}

// Claim a pool slot: the first inactive entry, else the oldest active one.
dynamic takeFx(pool) {
  var best = null;
  var bestLife = 9999.0;
  for (var fx in pool) {
    if (!fx.active) {
      return fx;
    }
    if (fx.life < bestLife) {
      bestLife = fx.life;
      best = fx;
    }
  }
  return best;
}

void fxTracer(double fx0, double fy0, double fz0, double tx, double ty, double tz) {
  var fx = takeFx(tracers);
  if (fx == null) {
    return;
  }
  var dx = tx - fx0;
  var dy = ty - fy0;
  var dz = tz - fz0;
  var dist = vlen3(dx, dy, dz);
  if (dist < 0.4) {
    return;
  }
  fx.active = true;
  fx.life = 0.07;
  fx.maxLife = 0.07;
  GD.beginBatch();
  fx.node.set("visible", true);
  fx.node.set("position",
      Vector3(fx0 + dx / 2.0, fy0 + dy / 2.0, fz0 + dz / 2.0));
  fx.node.call("look_at", [Vector3(tx, ty, tz)]);
  fx.node.set("scale", Vector3(1.0, 1.0, dist));
  GD.endBatch();
}

void fxImpact(double x, double y, double z) {
  var fx = takeFx(impacts);
  if (fx == null) {
    return;
  }
  fx.active = true;
  fx.life = 0.22;
  fx.maxLife = 0.22;
  GD.beginBatch();
  fx.node.set("visible", true);
  fx.node.set("position", Vector3(x, y, z));
  fx.node.set("scale", Vector3(1.0, 1.0, 1.0));
  GD.endBatch();
}

void fxPopup(double x, double y, double z, String text, Color col) {
  var fx = takeFx(popups);
  if (fx == null) {
    return;
  }
  fx.active = true;
  fx.life = 0.7;
  fx.maxLife = 0.7;
  GD.beginBatch();
  fx.node.set("text", text);
  fx.node.set("modulate", col);
  fx.node.set("position", Vector3(x + frandRange(-0.15, 0.15), y, z));
  fx.node.set("visible", true);
  GD.endBatch();
}

void updateEffects(double delta) {
  var any = false;
  for (var fx in tracers) {
    if (fx.active) {
      any = true;
    }
  }
  for (var fx in impacts) {
    if (fx.active) {
      any = true;
    }
  }
  for (var fx in popups) {
    if (fx.active) {
      any = true;
    }
  }
  if (muzzleEnergy > 0.01) {
    any = true;
  }
  if (!any) {
    return;
  }
  GD.beginBatch();
  for (var fx in tracers) {
    if (fx.active) {
      fx.life = fx.life - delta;
      if (fx.life <= 0.0) {
        fx.active = false;
        fx.node.set("visible", false);
      }
    }
  }
  for (var fx in impacts) {
    if (fx.active) {
      fx.life = fx.life - delta;
      if (fx.life <= 0.0) {
        fx.active = false;
        fx.node.set("visible", false);
      } else {
        var t = 1.0 - fx.life / fx.maxLife;
        var s = 1.0 + t * 3.0;
        fx.node.set("scale", Vector3(s, s, s));
        fx.extra.set("albedo_color", Color(1.0, 0.6, 0.25, 0.9 * (1.0 - t)));
      }
    }
  }
  for (var fx in popups) {
    if (fx.active) {
      fx.life = fx.life - delta;
      if (fx.life <= 0.0) {
        fx.active = false;
        fx.node.set("visible", false);
      } else {
        var p = fx.node.get("position");
        // Under the mock (or a dropped frame) the read is null â€” skip the rise.
        if (p is Vector3) {
          fx.node.set("position", Vector3(p.x, p.y + delta * 1.4, p.z));
        }
      }
    }
  }
  if (muzzleEnergy > 0.01) {
    muzzleEnergy = muzzleEnergy * (1.0 - clampf(14.0 * delta, 0.0, 1.0));
    if (muzzleEnergy < 0.01) {
      muzzleEnergy = 0.0;
    }
    muzzleLight.set("light_energy", GFloat(muzzleEnergy));
  }
  GD.endBatch();
}

