dynamic uiRect(parent, double x, double y, double w, double h, Color col) {
  var r = GD.create("ColorRect");
  r.set("position", Vector2(x, y));
  r.set("size", Vector2(w, h));
  r.set("color", col);
  r.set("mouse_filter", GInt(C["MOUSE_IGNORE"]));
  parent.call("add_child", [r]);
  return r;
}

dynamic uiLabel(parent, double x, double y, int size, Color col, String text) {
  var l = GD.create("Label");
  l.set("position", Vector2(x, y));
  l.set("text", text);
  l.set("theme_override_font_sizes/font_size", GInt(size));
  l.set("theme_override_colors/font_color", col);
  l.set("theme_override_colors/font_outline_color", Color(0.02, 0.03, 0.05, 0.85));
  l.set("theme_override_constants/outline_size", GInt(size ~/ 5));
  l.set("mouse_filter", GInt(C["MOUSE_IGNORE"]));
  parent.call("add_child", [l]);
  return l;
}

dynamic uiButton(parent, double x, double y, double w, double h, String text,
    int fontSize) {
  var b = GD.create("Button");
  b.set("position", Vector2(x, y));
  b.set("custom_minimum_size", Vector2(w, h));
  b.set("size", Vector2(w, h));
  b.set("text", text);
  b.set("theme_override_font_sizes/font_size", GInt(fontSize));
  parent.call("add_child", [b]);
  return b;
}

// An anchored container Control (children position relative to the anchor).
dynamic uiAnchor(parent, int preset) {
  var c = GD.create("Control");
  c.set("mouse_filter", GInt(C["MOUSE_IGNORE"]));
  parent.call("add_child", [c]);
  c.call("set_anchors_preset", [GInt(preset)]);
  return c;
}

// A rounded translucent panel (menu cards, touch buttons).
dynamic uiPanel(parent, double x, double y, double w, double h, Color bg,
    double radius) {
  var p = GD.create("Panel");
  var sb = GD.create("StyleBoxFlat");
  sb.set("bg_color", bg);
  sb.set("corner_radius_top_left", GInt(floor(radius)));
  sb.set("corner_radius_top_right", GInt(floor(radius)));
  sb.set("corner_radius_bottom_left", GInt(floor(radius)));
  sb.set("corner_radius_bottom_right", GInt(floor(radius)));
  p.call("add_theme_stylebox_override", ["panel", sb]);
  p.set("position", Vector2(x, y));
  p.set("size", Vector2(w, h));
  p.set("mouse_filter", GInt(C["MOUSE_IGNORE"]));
  parent.call("add_child", [p]);
  return p;
}

