void setKillFeed(String line) {
  // scroll up: 0 is the newest slot
  var i = killFeed.length - 1;
  while (i > 0) {
    var below = killFeed[i - 1];
    var slot = killFeed[i];
    slot[1] = below[1];
    slot[0].call("set", ["text", below[0].call("get", ["text"])]);
    i = i - 1;
  }
  killFeed[0][0].set("text", line);
  killFeed[0][1] = 3.0;
}

void showBanner(String text) {
  bannerLife = 2.4;
  hud["banner"].set("text", text);
}

void refreshHud() {
  if (!hudDirty) {
    return;
  }
  hudDirty = false;
  var w = weapons[currentWeapon];
  GD.beginBatch();
  hud["hpBar"].set("size", Vector2(328.0 * clampf(hp / MAX_HP, 0.0, 1.0), 20.0));
  var hpFrac = hp / MAX_HP;
  hud["hpBar"].set("color", hpFrac > 0.35
      ? Color(0.35, 0.95, 0.5, 0.95)
      : Color(1.0, 0.35, 0.25, 0.95));
  hud["weapon"].set("text", w.name);
  hud["ammo"].set("text", "" + w.mag + " / " + w.reserve);
  hud["wave"].set("text", wave > 0 ? "WAVE " + wave : "STANDBY");
  hud["score"].set("text", "SCORE " + score);
  hud["kills"].set("text", "KILLS " + kills);
  hud["hint"].set("theme_override_colors/font_color",
      reloading > 0.0 ? Color(1.0, 0.55, 0.3, 1.0) : Color(1.0, 0.55, 0.3, 0.0));
  GD.endBatch();
}

// Per-frame HUD animation (fades) â€” batched, only when something is live.
void animateHud(double delta) {
  var any = vignetteAlpha > 0.003 || hitmarkerLife > 0.0 || bannerLife > 0.0;
  for (var slot in killFeed) {
    if (slot[1] > 0.0) {
      any = true;
    }
  }
  if (!any) {
    return;
  }
  GD.beginBatch();
  if (vignetteAlpha > 0.003) {
    vignetteAlpha = vignetteAlpha * (1.0 - clampf(3.5 * delta, 0.0, 1.0));
    if (vignetteAlpha <= 0.003) {
      vignetteAlpha = 0.0;
    }
    hud["vignette"].set("color", Color(0.75, 0.05, 0.05, vignetteAlpha));
  }
  if (hitmarkerLife > 0.0) {
    hitmarkerLife = hitmarkerLife - delta;
    var a = clampf(hitmarkerLife / 0.18, 0.0, 1.0);
    var col = Color(1.0, 0.35, 0.25, a);
    hud["hm1"].set("color", col);
    hud["hm2"].set("color", col);
    hud["hm3"].set("color", col);
    hud["hm4"].set("color", col);
  }
  if (bannerLife > 0.0) {
    bannerLife = bannerLife - delta;
    var a = clampf(bannerLife, 0.0, 1.0);
    hud["banner"].set("theme_override_colors/font_color",
        Color(1.0, 0.85, 0.4, a));
  }
  for (var slot in killFeed) {
    if (slot[1] > 0.0) {
      slot[1] = slot[1] - delta;
      var a = clampf(slot[1], 0.0, 1.0);
      slot[0].set("theme_override_colors/font_color", Color(1.0, 1.0, 1.0, a));
    }
  }
  GD.endBatch();
}

