// ---------------------------------------------------------------------------
// input: desktop polling + event routing (mouse, keys, touch)
// ---------------------------------------------------------------------------

var desktopFire = false;
var desktopAim = false;

void setMouseCaptured(bool captured) {
  if (!(inputSingleton is GObj)) {
    return;
  }
  inputSingleton.call("set_mouse_mode",
      [captured ? C["MOUSE_CAPTURED"] : C["MOUSE_VISIBLE"]]);
  mouseCaptured = captured;
}

// One seam crossing polls every key/button the controller uses this frame.
void pollDesktopInput() {
  if (touchMode) {
    // touch devices drive everything through the on-screen controls
    inMoveX = stickVecX;
    inMoveZ = stickVecY;
    inSprint = vlen3(stickVecX, 0.0, stickVecY) > 0.92;
    return;
  }
  if (!(inputSingleton is GObj)) {
    return;
  }
  GD.beginBatch();
  inputSingleton.call("is_physical_key_pressed", [C["KEY_W"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_A"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_S"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_D"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_SPACE"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_SHIFT"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_R"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_Q"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_1"]]);
  inputSingleton.call("is_physical_key_pressed", [C["KEY_2"]]);
  inputSingleton.call("is_mouse_button_pressed", [C["MOUSE_BUTTON_LEFT"]]);
  inputSingleton.call("is_mouse_button_pressed", [C["MOUSE_BUTTON_RIGHT"]]);
  var r = GD.endBatch();
  if (!(r is List)) {
    return;
  }
  if (r.length < 12) {
    return;
  }
  var mz = 0.0;
  var mx = 0.0;
  if (r[0] == true) {
    mz = mz - 1.0;
  }
  if (r[2] == true) {
    mz = mz + 1.0;
  }
  if (r[1] == true) {
    mx = mx - 1.0;
  }
  if (r[3] == true) {
    mx = mx + 1.0;
  }
  inMoveX = mx;
  inMoveZ = mz;
  if (r[4] == true && !inJumpPrev) {
    inJump = true;
  }
  inJumpPrev = r[4] == true;
  inSprint = r[5] == true;
  if (r[6] == true && !inReloadPrev) {
    inReload = true;
  }
  inReloadPrev = r[6] == true;
  var q = r[7] == true;
  if (q && !inSwitchPrev) {
    switchWeapon(1);
  }
  inSwitchPrev = q;
  if (r[8] == true) {
    setWeapon(0);
  }
  if (r[9] == true) {
    setWeapon(1);
  }
  desktopFire = r[10] == true;
  desktopAim = r[11] == true;
}

// Route one InputEvent from the engine. Every branch reads its fields and
// releases the event handle in a single batched crossing.
void handleInput(event) {
  if (!(event is GObj)) {
    return;
  }
  var cls = event.cls;
  if (cls == "InputEventMouseMotion") {
    if (mouseCaptured && mode == "playing") {
      GD.beginBatch();
      event.get("relative");
      event.release();
      var r = GD.endBatch();
      if (r is List) {
        if (r.length > 0) {
          var rel = r[0];
          if (rel is Vector2) {
            lookDX = lookDX + rel.x;
            lookDY = lookDY + rel.y;
          }
        }
      }
    } else {
      event.release();
    }
    return;
  }
  if (cls == "InputEventKey") {
    GD.beginBatch();
    event.get("keycode");
    event.get("pressed");
    event.get("echo");
    event.release();
    var r = GD.endBatch();
    if (r is List) {
      if (r.length >= 3) {
        if (r[1] == true && r[2] != true && r[0] == C["KEY_ESCAPE"]) {
          if (mode == "playing") {
            togglePause();
          } else if (mode == "paused") {
            togglePause();
          }
        }
      }
    }
    return;
  }
  if (cls == "InputEventMouseButton") {
    GD.beginBatch();
    event.get("button_index");
    event.get("pressed");
    event.release();
    var r = GD.endBatch();
    if (r is List) {
      if (r.length >= 2 && r[1] == true) {
        if (r[0] == C["MOUSE_BUTTON_WHEEL_UP"]) {
          switchWeapon(1);
        } else if (r[0] == C["MOUSE_BUTTON_WHEEL_DOWN"]) {
          switchWeapon(1);
        } else if (mode == "playing" && !mouseCaptured && !touchMode) {
          // clicked back into the window (web pointer-lock re-entry)
          setMouseCaptured(true);
        }
      }
    }
    return;
  }
  if (cls == "InputEventScreenTouch") {
    GD.beginBatch();
    event.get("position");
    event.get("pressed");
    event.get("index");
    if (vpNode is GObj) {
      vpNode.call("get_visible_rect", []);
    }
    event.release();
    var r = GD.endBatch();
    if (r is List) {
      if (r.length >= 3) {
        var pos = r[0];
        var pressed = r[1] == true;
        var idx = r[2];
        if (r.length >= 5) {
          var rect = r[3];
          if (rect is Rect2) {
            screenW = rect.w;
            screenH = rect.h;
          }
        }
        if ((pos is Vector2) && (idx is num)) {
          onTouch(pos.x, pos.y, pressed, floor(idx));
        }
      }
    }
    return;
  }
  if (cls == "InputEventScreenDrag") {
    GD.beginBatch();
    event.get("position");
    event.get("relative");
    event.get("index");
    event.release();
    var r = GD.endBatch();
    if (r is List) {
      if (r.length >= 3) {
        var pos = r[0];
        var rel = r[1];
        var idx = r[2];
        if ((pos is Vector2) && (idx is num)) {
          var relX = 0.0;
          var relY = 0.0;
          if (rel is Vector2) {
            relX = rel.x;
            relY = rel.y;
          }
          onDrag(pos.x, pos.y, relX, relY, floor(idx));
        }
      }
    }
    return;
  }
  event.release();
}

void setStickFromTouch(double x, double y) {
  var baseX = 170.0;
  var baseY = screenH - 160.0;
  var dx = x - baseX;
  var dy = y - baseY;
  var len = vlen3(dx, 0.0, dy);
  if (len > 90.0) {
    dx = dx * 90.0 / len;
    dy = dy * 90.0 / len;
  }
  stickVecX = dx / 90.0;
  stickVecY = dy / 90.0;
  if (stickKnob is GObj) {
    stickKnob.set("position",
        Vector2(stickBaseX - 40.0 + dx, stickBaseY - 720.0 - 40.0 + dy));
  }
}

void resetStick() {
  stickVecX = 0.0;
  stickVecY = 0.0;
  if (stickKnob is GObj) {
    stickKnob.set("position",
        Vector2(stickBaseX - 40.0, stickBaseY - 720.0 - 40.0));
  }
}

void onTouch(double x, double y, bool pressed, int idx) {
  if (!touchMode || mode != "playing") {
    return;
  }
  var key = "i" + idx;
  if (pressed) {
    if (x < 480.0 && y > screenH * 0.42) {
      touchRoles[key] = "stick";
      setStickFromTouch(x, y);
    } else if (x > screenW - 420.0 && y > screenH * 0.2) {
      touchRoles[key] = "ui"; // the action buttons own this touch
    } else {
      touchRoles[key] = "look";
    }
  } else {
    if (touchRoles[key] == "stick") {
      resetStick();
    }
    touchRoles[key] = "";
  }
}

void onDrag(double x, double y, double relX, double relY, int idx) {
  if (!touchMode || mode != "playing") {
    return;
  }
  var role = touchRoles["i" + idx];
  if (role == "stick") {
    setStickFromTouch(x, y);
  } else if (role == "look") {
    lookDX = lookDX + relX * 1.9;
    lookDY = lookDY + relY * 1.9;
  }
}

// ---------------------------------------------------------------------------
// weapons: switching, reloading, firing
// ---------------------------------------------------------------------------

void setWeapon(int ix) {
  if (ix == currentWeapon || ix < 0 || ix >= weapons.length) {
    return;
  }
  currentWeapon = ix;
  reloading = 0.0;
  fireCooldown = 0.25;
  var i = 0;
  while (i < weaponNodes.length) {
    var node = weaponNodes[i];
    if (node is GObj) {
      node.set("visible", i == currentWeapon);
    }
    i = i + 1;
  }
  playSfx("empty", -12.0, 1.15, 1.25);
  hudDirty = true;
}

void switchWeapon(int dir) {
  setWeapon((currentWeapon + dir) % weapons.length);
}

void startReload() {
  var w = weapons[currentWeapon];
  if (reloading > 0.0 || w.reserve <= 0 || w.mag >= w.magSize) {
    return;
  }
  reloading = w.reloadTime;
  playSfx("reload", -6.0, 0.95, 1.05);
  hudDirty = true;
}

void finishReload() {
  var w = weapons[currentWeapon];
  var want = w.magSize - w.mag;
  var take = want < w.reserve ? want : w.reserve;
  w.mag = w.mag + take;
  w.reserve = w.reserve - take;
  hudDirty = true;
}

// Current view-forward from yaw/pitch (camera and gun share it).
dynamic viewForward() {
  var cp = cos(pitch);
  return [0.0 - cp * sin(yaw), sin(pitch), 0.0 - cp * cos(yaw)];
}

dynamic muzzleWorld() {
  var f = viewForward();
  var rx = cos(yaw);
  var rz = 0.0 - sin(yaw);
  return [
    px + f[0] * 0.9 + rx * 0.3,
    py + EYE_HEIGHT + f[1] * 0.9 - 0.18,
    pz + f[2] * 0.9 + rz * 0.3,
  ];
}

void tryFire() {
  var w = weapons[currentWeapon];
  if (fireCooldown > 0.0 || reloading > 0.0) {
    return;
  }
  if (w.mag <= 0) {
    playSfx("empty", -8.0, 0.95, 1.05);
    fireCooldown = 0.3;
    if (w.reserve > 0) {
      startReload();
    }
    return;
  }
  w.mag = w.mag - 1;
  fireCooldown = 1.0 / w.rof;
  shotsFired = shotsFired + 1;
  fireAnimTime = 0.22;
  hudDirty = true;

  // hitscan through the physics space with a spread cone
  var spread = w.spread * (aiming ? 0.35 : 1.0) + (sprinting ? 0.02 : 0.0);
  var f = viewForward();
  var dx = f[0] + frandRange(0.0 - spread, spread);
  var dy = f[1] + frandRange(0.0 - spread, spread);
  var dz = f[2] + frandRange(0.0 - spread, spread);
  var ox = px;
  var oy = py + EYE_HEIGHT;
  var oz = pz;
  var range = 140.0;
  var ex = ox + dx * range;
  var ey = oy + dy * range;
  var ez = oz + dz * range;

  var hit = castRay(ox, oy, oz, ex, ey, ez, 5, playerRid);
  var hitSomething = false;
  if (hit is Map) {
    var hp3 = hit["position"];
    if (hp3 is Vector3) {
      ex = hp3.x;
      ey = hp3.y;
      ez = hp3.z;
      hitSomething = true;
    }
    var collider = hit["collider"];
    if (collider is GObj) {
      var ix = collider.call("get_meta", ["enemy_ix", GInt(-1)]);
      if ((ix is num) && ix >= 0) {
        var fi = floor(ix);
        if (fi < foes.length) {
          var foe = foes[fi];
          var headshot = hitSomething && (ey - foe.y) > 1.42;
          damageEnemy(fi, w.damage * (headshot ? 2.0 : 1.0), ex, ey, ez, headshot);
        }
      } else if (hitSomething) {
        fxImpact(ex, ey, ez);
      }
    } else if (hitSomething) {
      fxImpact(ex, ey, ez);
    }
  }

  // muzzle flash + tracer + kick
  var m = muzzleWorld();
  fxTracer(m[0], m[1], m[2], ex, ey, ez);
  muzzleEnergy = 2.6;
  GD.beginBatch();
  muzzleLight.set("position", Vector3(m[0], m[1], m[2]));
  muzzleLight.set("light_energy", GFloat(muzzleEnergy));
  GD.endBatch();
  var kick = currentWeapon == 1 ? 0.035 : 0.011;
  pitch = clampf(pitch + kick, PITCH_MIN, PITCH_MAX);
  camShake = clampf(camShake + kick * 3.0, 0.0, 0.4);
  playSfx(currentWeapon == 1 ? "heavy" : "shot", -4.0, 0.92, 1.08);
}

// ---------------------------------------------------------------------------
// player damage / health
// ---------------------------------------------------------------------------

void damagePlayer(double dmg) {
  if (mode != "playing") {
    return;
  }
  hp = hp - dmg;
  lastDamageAt = elapsed;
  vignetteAlpha = 0.5;
  camShake = clampf(camShake + 0.18, 0.0, 0.5);
  playSfx("hurt", -4.0, 0.9, 1.1);
  hudDirty = true;
  if (hp <= 0.0) {
    hp = 0.0;
    gameOver();
  }
}

// ---------------------------------------------------------------------------
// player frame update (movement, camera, weapon timers) â€” one batch crossing
// ---------------------------------------------------------------------------

var rigX = 0.0;
var rigY = 1.5;
var rigZ = 0.0;

void updatePlayer(double delta) {
  // ---- look -----------------------------------------------------------------
  var sens = MOUSE_SENS;
  yaw = yaw - lookDX * sens;
  pitch = clampf(pitch - lookDY * sens, PITCH_MIN, PITCH_MAX);
  lookDX = 0.0;
  lookDY = 0.0;

  // ---- weapon timers / trigger ----------------------------------------------
  var w = weapons[currentWeapon];
  if (fireCooldown > 0.0) {
    fireCooldown = fireCooldown - delta;
  }
  if (fireAnimTime > 0.0) {
    fireAnimTime = fireAnimTime - delta;
  }
  if (reloading > 0.0) {
    reloading = reloading - delta;
    if (reloading <= 0.0) {
      reloading = 0.0;
      finishReload();
    }
  }
  aiming = desktopAim || touchAim;
  triggerHeld = desktopFire || touchFire;
  if (triggerHeld && (w.auto || !triggerWasHeld)) {
    tryFire();
  }
  triggerWasHeld = triggerHeld;
  if (inReload) {
    startReload();
  }

  // ---- movement -------------------------------------------------------------
  var ix = clampf(inMoveX, -1.0, 1.0);
  var iz = clampf(inMoveZ, -1.0, 1.0);
  var ilen = vlen3(ix, 0.0, iz);
  if (ilen > 1.0) {
    ix = ix / ilen;
    iz = iz / ilen;
  }
  var moving = ilen > 0.08;
  sprinting = inSprint && moving && !aiming && reloading <= 0.0;
  var speed = aiming ? AIM_SPEED : (sprinting ? SPRINT_SPEED : WALK_SPEED);
  var wx = ix * cos(yaw) + iz * sin(yaw);
  var wz = 0.0 - ix * sin(yaw) + iz * cos(yaw);
  var blend = clampf(ACCEL * delta, 0.0, 1.0);
  vx = lerp(vx, wx * speed, blend);
  vz = lerp(vz, wz * speed, blend);
  vy = vy - GRAVITY * delta;
  if (inJump && onFloor) {
    vy = JUMP_VEL;
    playSfx("empty", -16.0, 0.7, 0.8);
  }

  // Dart-side prediction: authoritative under the mock, replaced by the real
  // body position when the engine answers.
  px = px + vx * delta;
  py = py + vy * delta;
  pz = pz + vz * delta;
  var predictedFloor = false;
  if (py <= ROAD_Y) {
    py = ROAD_Y;
    if (vy < 0.0) {
      vy = 0.0;
    }
    predictedFloor = true;
  }
  px = clampf(px, -66.0, 66.0);
  pz = clampf(pz, -66.0, 66.0);

  // ---- camera targets --------------------------------------------------------
  rigX = lerp(rigX, px, clampf(14.0 * delta, 0.0, 1.0));
  rigY = lerp(rigY, py + EYE_HEIGHT, clampf(14.0 * delta, 0.0, 1.0));
  rigZ = lerp(rigZ, pz, clampf(14.0 * delta, 0.0, 1.0));
  var targetSpring = aiming ? CAM_DIST_AIM : CAM_DIST;
  springCurrent = lerp(springCurrent, targetSpring, clampf(10.0 * delta, 0.0, 1.0));
  var targetFov = aiming ? FOV_AIM : (sprinting ? FOV_SPRINT : FOV_BASE);
  fovCurrent = lerp(fovCurrent, targetFov, clampf(8.0 * delta, 0.0, 1.0));
  camShake = camShake * (1.0 - clampf(6.0 * delta, 0.0, 1.0));
  var shakeP = frandRange(0.0 - camShake, camShake) * 0.05;
  var shakeR = frandRange(0.0 - camShake, camShake) * 0.04;

  // model faces the move direction; combat locks it to the camera
  var wantYaw = modelYaw;
  if (aiming || triggerHeld || fireAnimTime > 0.0) {
    wantYaw = yaw;
  } else if (moving) {
    wantYaw = atan2(0.0 - vx, 0.0 - vz);
  }
  modelYaw = approachAngle(modelYaw, wantYaw, 10.0 * delta);

  // animation state
  var animWant = "holding-right";
  if (fireAnimTime > 0.0) {
    animWant = "holding-right-shoot";
  } else if (moving && sprinting) {
    animWant = "sprint";
  } else if (moving) {
    animWant = "walk";
  }
  playerAnimState = driveAnim(playerAnim, playerAnimState, animWant);

  // ---- health regen ----------------------------------------------------------
  if (hp > 0.0 && hp < MAX_HP && elapsed - lastDamageAt > REGEN_DELAY) {
    var before = floor(hp);
    hp = clampf(hp + REGEN_RATE * delta, 0.0, MAX_HP);
    if (floor(hp) != before) {
      hudDirty = true;
    }
  }

  // ---- one batched crossing: physics + camera + model ------------------------
  GD.beginBatch();
  playerBody.set("velocity", Vector3(vx, vy, vz)); // op 0
  playerBody.call("move_and_slide", []); // op 1
  playerBody.call("is_on_floor", []); // op 2
  playerBody.call("get_position", []); // op 3
  camRig.set("position", Vector3(rigX, rigY, rigZ));
  camYawNode.set("rotation", Vector3(0.0, yaw, 0.0));
  camPitchNode.set("rotation", Vector3(pitch + shakeP, 0.0, shakeR));
  camSpring.set("spring_length", GFloat(springCurrent));
  camera.set("fov", GFloat(fovCurrent));
  playerModel.set("rotation", Vector3(0.0, modelYaw, 0.0));
  var res = GD.endBatch();
  if ((res is List) && res.length >= 4) {
    var p = res[3];
    if (p is Vector3) {
      px = p.x;
      py = p.y;
      pz = p.z;
      onFloor = res[2] == true;
    } else {
      onFloor = predictedFloor;
    }
  } else {
    onFloor = predictedFloor;
  }
}

// ---------------------------------------------------------------------------
// enemies
// ---------------------------------------------------------------------------

int liveFoeCount() {
  var n = 0;
  for (var f in foes) {
    if (f.state != "dead") {
      n = n + 1;
    }
  }
  return n;
}

void spawnFoe(String kind) {
  // pick a road intersection well away from the player
  var sx = 30.0;
  var sz = 30.0;
  if (spawnPoints.length > 0) {
    var tries = 0;
    var found = false;
    while (tries < 10 && !found) {
      var sp = spawnPoints[floor(frand() * spawnPoints.length) % spawnPoints.length];
      var dx = sp[0] - px;
      var dz = sp[1] - pz;
      if (vlen3(dx, 0.0, dz) >= 22.0) {
        sx = sp[0];
        sz = sp[1];
        found = true;
      }
      tries = tries + 1;
    }
  }

  var f = Foe(kind);
  var charKey = "char-grunt";
  var gunKey = "gun-enemy";
  var tint = Color(0.75, 0.3, 0.25, 1.0);
  if (kind == "grunt") {
    f.maxHp = 60.0;
    f.speed = 3.6;
    f.damage = 7.0;
    charKey = frand() < 0.5 ? "char-grunt" : "char-grunt2";
  } else if (kind == "runner") {
    f.maxHp = 35.0;
    f.speed = 6.2;
    f.damage = 5.0;
    charKey = "char-runner";
    tint = Color(0.85, 0.55, 0.2, 1.0);
  } else {
    f.maxHp = 150.0;
    f.speed = 2.5;
    f.damage = 15.0;
    charKey = "char-heavy";
    gunKey = "gun-heavy";
    tint = Color(0.45, 0.2, 0.5, 1.0);
  }
  f.hp = f.maxHp;
  f.x = sx;
  f.y = ROAD_Y;
  f.z = sz;
  f.heading = frandRange(0.0, PI * 2.0);
  f.strafeDir = frand() < 0.5 ? 1.0 : -1.0;

  var body = GD.create("CharacterBody3D");
  GD.beginBatch();
  var col = GD.create("CollisionShape3D");
  var shape = GD.create("CapsuleShape3D");
  shape.set("radius", GFloat(0.38));
  shape.set("height", GFloat(1.8));
  col.set("shape", shape);
  col.set("position", Vector3(0.0, 0.95, 0.0));
  body.call("add_child", [col]);
  body.set("collision_layer", GInt(4));
  body.set("collision_mask", GInt(7));
  body.set("position", Vector3(sx, ROAD_Y, sz));
  body.call("set_meta", ["enemy_ix", GInt(foes.length)]);
  GD.mount(body);
  GD.endBatch();
  f.body = body;
  f.rid = body.call("get_rid", []);

  var rig = buildCharacter(charKey, gunKey, tint);
  f.model = rig[0];
  f.anim = rig[1];
  body.call("add_child", [f.model]);
  f.animState = driveAnim(f.anim, f.animState, "walk");

  // billboard health bar
  GD.beginBatch();
  var hbBg = GD.create("MeshInstance3D");
  var bgQuad = GD.create("QuadMesh");
  var bgMat = GD.create("StandardMaterial3D");
  bgQuad.set("size", Vector2(1.05, 0.11));
  bgMat.set("albedo_color", Color(0.22, 0.04, 0.04, 1.0));
  bgMat.set("billboard_mode", C["BILLBOARD"]);
  bgMat.set("shading_mode", C["SHADED_OFF"]);
  bgMat.set("no_depth_test", true);
  bgQuad.set("material", bgMat);
  hbBg.set("mesh", bgQuad);
  hbBg.set("position", Vector3(0.0, 2.15, 0.0));
  body.call("add_child", [hbBg]);
  var hbFg = GD.create("MeshInstance3D");
  var fgQuad = GD.create("QuadMesh");
  var fgMat = GD.create("StandardMaterial3D");
  fgQuad.set("size", Vector2(1.0, 0.075));
  fgMat.set("albedo_color", Color(0.95, 0.25, 0.2, 1.0));
  fgMat.set("billboard_mode", C["BILLBOARD"]);
  fgMat.set("shading_mode", C["SHADED_OFF"]);
  fgMat.set("no_depth_test", true);
  fgQuad.set("material", fgMat);
  hbFg.set("mesh", fgQuad);
  hbFg.set("position", Vector3(0.0, 2.15, 0.01));
  body.call("add_child", [hbFg]);
  GD.endBatch();
  f.hbBg = hbBg;
  f.hbFg = hbFg;

  foes.add(f);
}

void damageEnemy(int ix, double dmg, double hx, double hy, double hz, bool headshot) {
  if (ix < 0 || ix >= foes.length) {
    return;
  }
  var f = foes[ix];
  if (f.state == "dead") {
    return;
  }
  f.hp = f.hp - dmg;
  shotsHit = shotsHit + 1;
  hitmarkerLife = 0.18;
  playSfx("hit", -8.0, headshot ? 1.25 : 0.95, headshot ? 1.4 : 1.1);
  fxPopup(hx, hy + 0.25, hz, "" + floor(dmg),
      headshot ? Color(1.0, 0.65, 0.15, 1.0) : Color(1.0, 1.0, 1.0, 0.95));
  if (f.hbFg is GObj) {
    var frac = clampf(f.hp / f.maxHp, 0.0, 1.0);
    f.hbFg.set("scale", Vector3(frac < 0.02 ? 0.02 : frac, 1.0, 1.0));
  }
  if (f.hp <= 0.0) {
    killFoe(f, headshot);
  } else if (f.state == "chase" && frand() < 0.4) {
    // getting shot provokes an early attack posture
    f.state = "attack";
    f.stateTime = 0.0;
    f.shootTimer = frandRange(0.4, 0.9);
  }
}

void killFoe(f, bool headshot) {
  f.state = "dead";
  f.deadTime = 0.0;
  kills = kills + 1;
  var pts = 100;
  if (f.kind == "runner") {
    pts = 150;
  }
  if (f.kind == "heavy") {
    pts = 250;
  }
  if (headshot) {
    pts = pts + 50;
  }
  score = score + pts;
  hudDirty = true;
  setKillFeed((headshot ? "HEADSHOT  " : "HOSTILE DOWN  ") + "+" + pts);
  f.animState = driveAnim(f.anim, f.animState, "die");
  GD.beginBatch();
  f.body.set("collision_layer", GInt(0));
  f.body.set("collision_mask", GInt(0));
  if (f.hbBg is GObj) {
    f.hbBg.set("visible", false);
  }
  if (f.hbFg is GObj) {
    f.hbFg.set("visible", false);
  }
  GD.endBatch();
  playSfx("death", -7.0, 0.95, 1.1);
  if (frand() < 0.35) {
    spawnPickup(frand() < 0.5 ? "health" : "ammo", f.x, f.z);
  }
  print("[tps] hostile down (" + f.kind + ") +" + pts + " score=" + score);
}

// One enemy fires one shot at the player: LOS check, accuracy roll, tracer.
void foeShoot(f) {
  var ex = f.x;
  var ey = f.y + 1.35;
  var ez = f.z;
  var tx = px;
  var ty = py + 1.3;
  var tz = pz;
  var dist = vlen3(tx - ex, ty - ey, tz - ez);

  var blocked = false;
  var hit = castRay(ex, ey, ez, tx, ty, tz, 3, f.rid);
  if (hit is Map) {
    var collider = hit["collider"];
    if (collider is GObj) {
      var isPlayer = collider.call("get_meta", ["is_player", false]);
      if (isPlayer != true) {
        blocked = true;
        var bp = hit["position"];
        if (bp is Vector3) {
          fxTracer(ex, ey, ez, bp.x, bp.y, bp.z);
          fxImpact(bp.x, bp.y, bp.z);
        }
      }
    }
  }
  if (blocked) {
    // lost the shot behind cover â€” resume the chase
    f.state = "chase";
    f.stateTime = 0.0;
    return;
  }

  var acc = 0.34;
  if (f.kind == "heavy") {
    acc = 0.42;
  }
  if (f.kind == "runner") {
    acc = 0.26;
  }
  acc = acc * clampf(1.25 - dist * 0.03, 0.35, 1.0);
  if (frand() < acc) {
    fxTracer(ex, ey, ez, tx, ty, tz);
    damagePlayer(f.damage);
  } else {
    fxTracer(ex, ey, ez, tx + frandRange(-1.6, 1.6), ty + frandRange(-0.8, 1.2),
        tz + frandRange(-1.6, 1.6));
  }
  playSfx("shot", -13.0, 0.72, 0.82);
}

void updateFoes(double delta) {
  // 1) think (Dart only): states, headings, timers; collect shooters
  var shooters = [];
  for (var f in foes) {
    if (f.state == "dead") {
      f.deadTime = f.deadTime + delta;
    } else {
      f.stateTime = f.stateTime + delta;
      var dx = px - f.x;
      var dz = pz - f.z;
      var dist = vlen3(dx, 0.0, dz);
      var toPlayer = atan2(0.0 - dx, 0.0 - dz);
      if (f.state == "spawn") {
        if (f.stateTime > 0.6) {
          f.state = "chase";
          f.stateTime = 0.0;
        }
        f.vxw = 0.0;
        f.vzw = 0.0;
      } else if (f.state == "chase") {
        var nx = dist > 0.01 ? dx / dist : 0.0;
        var nz = dist > 0.01 ? dz / dist : 0.0;
        f.vxw = nx * f.speed;
        f.vzw = nz * f.speed;
        f.heading = approachAngle(f.heading, toPlayer, 8.0 * delta);
        if (dist < ENEMY_ATTACK_RANGE && f.stateTime > 0.4) {
          f.state = "attack";
          f.stateTime = 0.0;
          f.shootTimer = frandRange(0.3, 0.8);
        }
      } else if (f.state == "attack") {
        if (dist > ENEMY_ATTACK_RANGE * 1.35) {
          f.state = "chase";
          f.stateTime = 0.0;
        } else {
          var nx = dist > 0.01 ? dx / dist : 0.0;
          var nz = dist > 0.01 ? dz / dist : 0.0;
          // hold range and strafe
          var push = 0.15;
          if (dist < ENEMY_STOP_RANGE) {
            push = -0.45;
          }
          if (frand() < 0.008) {
            f.strafeDir = 0.0 - f.strafeDir;
          }
          var tanx = 0.0 - nz;
          var tanz = nx;
          f.vxw = nx * f.speed * push + tanx * f.speed * 0.4 * f.strafeDir;
          f.vzw = nz * f.speed * push + tanz * f.speed * 0.4 * f.strafeDir;
          f.heading = approachAngle(f.heading, toPlayer, 10.0 * delta);
          f.shootTimer = f.shootTimer - delta;
          if (f.shootTimer <= 0.0) {
            f.shootTimer = f.kind == "heavy"
                ? frandRange(1.2, 1.7)
                : frandRange(0.7, 1.2);
            shooters.add(f);
          }
        }
      }
      // Dart-side prediction (authoritative under the mock)
      f.x = clampf(f.x + f.vxw * delta, -66.0, 66.0);
      f.z = clampf(f.z + f.vzw * delta, -66.0, 66.0);
    }
  }

  // 2) animation transitions (rare; immediate ops)
  for (var f in foes) {
    if (f.state != "dead") {
      var want = "walk";
      if (f.state == "attack") {
        want = "holding-right-shoot";
      } else if (f.kind == "runner") {
        want = "sprint";
      }
      f.animState = driveAnim(f.anim, f.animState, want);
    }
  }

  // 3) one batched crossing moves every live body (+ buries the dead)
  var slots = [];
  var opN = 0;
  GD.beginBatch();
  for (var f in foes) {
    if (f.state == "dead") {
      if (f.body != null) {
        if (f.deadTime > 1.5) {
          // sink, then free
          f.body.set("position", Vector3(f.x, f.y - (f.deadTime - 1.5) * 0.8, f.z));
          opN = opN + 1;
          if (f.deadTime > 2.6) {
            f.body.queueFree();
            opN = opN + 1;
            f.body = null;
          }
        }
      }
    } else {
      f.body.set("velocity", Vector3(f.vxw, -2.0, f.vzw));
      opN = opN + 1;
      f.body.call("move_and_slide", []);
      opN = opN + 1;
      f.body.call("get_position", []);
      slots.add([f, opN]);
      opN = opN + 1;
      f.model.set("rotation", Vector3(0.0, f.heading, 0.0));
      opN = opN + 1;
    }
  }
  var res = GD.endBatch();
  if (res is List) {
    for (var s in slots) {
      var i = s[1];
      if (i < res.length) {
        var p = res[i];
        if (p is Vector3) {
          s[0].x = p.x;
          s[0].y = p.y;
          s[0].z = p.z;
        }
      }
    }
  }

  // 4) fire after the batch is closed (raycasts open their own batches)
  for (var f in shooters) {
    if (f.state == "attack" && mode == "playing") {
      foeShoot(f);
    }
  }
}

// ---------------------------------------------------------------------------
// pickups
// ---------------------------------------------------------------------------

void spawnPickup(String kind, double x, double z) {
  var p = Pick(kind);
  p.x = x;
  p.z = z;
  GD.beginBatch();
  var m = GD.create("MeshInstance3D");
  var box = GD.create("BoxMesh");
  var mat = GD.create("StandardMaterial3D");
  box.set("size", Vector3(0.5, 0.5, 0.5));
  if (kind == "health") {
    mat.set("albedo_color", Color(0.9, 0.95, 0.95, 1.0));
    mat.set("emission_enabled", true);
    mat.set("emission", Color(0.3, 1.0, 0.5, 1.0));
    mat.set("emission_energy_multiplier", GFloat(0.9));
  } else {
    mat.set("albedo_color", Color(0.25, 0.25, 0.28, 1.0));
    mat.set("emission_enabled", true);
    mat.set("emission", Color(1.0, 0.8, 0.25, 1.0));
    mat.set("emission_energy_multiplier", GFloat(0.9));
  }
  box.set("material", mat);
  m.set("mesh", box);
  m.set("position", Vector3(x, ROAD_Y + 0.6, z));
  GD.mount(m);
  GD.endBatch();
  p.node = m;
  pickups.add(p);
}

void updatePickups(double delta) {
  var anyAlive = false;
  for (var p in pickups) {
    if (p.alive) {
      anyAlive = true;
    }
  }
  if (!anyAlive) {
    return;
  }
  GD.beginBatch();
  for (var p in pickups) {
    if (p.alive) {
      p.spin = p.spin + delta * 2.2;
      p.node.set("rotation", Vector3(0.0, p.spin, 0.6));
      p.node.set("position",
          Vector3(p.x, ROAD_Y + 0.6 + 0.15 * sin(p.spin * 1.4), p.z));
    }
  }
  GD.endBatch();
  for (var p in pickups) {
    if (p.alive) {
      var d = vlen3(p.x - px, 0.0, p.z - pz);
      if (d < 1.5) {
        collectPickup(p);
      }
    }
  }
}

void collectPickup(p) {
  p.alive = false;
  p.node.queueFree();
  p.node = null;
  playSfx("pickup", -5.0, 0.98, 1.02);
  if (p.kind == "health") {
    hp = clampf(hp + 40.0, 0.0, MAX_HP);
    fxPopup(px, py + 2.0, pz, "+40 HP", Color(0.35, 1.0, 0.5, 1.0));
  } else {
    var w = weapons[currentWeapon];
    w.reserve = w.reserve + (currentWeapon == 1 ? 8 : 60);
    fxPopup(px, py + 2.0, pz, "+AMMO", Color(1.0, 0.85, 0.3, 1.0));
  }
  hudDirty = true;
}

// ---------------------------------------------------------------------------
// waves
// ---------------------------------------------------------------------------

String pickFoeKind() {
  if (wave >= 3 && pendingSpawns % 5 == 0) {
    return "heavy";
  }
  if (wave >= 2 && pendingSpawns % 3 == 0) {
    return "runner";
  }
  return "grunt";
}

void updateWaves(double delta) {
  if (intermission > 0.0) {
    intermission = intermission - delta;
    if (intermission <= 0.0) {
      intermission = 0.0;
      wave = wave + 1;
      pendingSpawns = 4 + wave * 2;
      if (pendingSpawns > 18) {
        pendingSpawns = 18;
      }
      spawnTimer = 0.4;
      showBanner("WAVE " + wave);
      playSfx("horn", -5.0, 1.0, 1.0);
      hudDirty = true;
      print("[tps] wave " + wave + " deployed (" + pendingSpawns + " hostiles)");
    }
    return;
  }
  if (pendingSpawns > 0) {
    if (liveFoeCount() < MAX_LIVE_ENEMIES) {
      spawnTimer = spawnTimer - delta;
      if (spawnTimer <= 0.0) {
        spawnTimer = 0.75;
        spawnFoe(pickFoeKind());
        pendingSpawns = pendingSpawns - 1;
      }
    }
    return;
  }
  if (liveFoeCount() == 0) {
    score = score + 250;
    hudDirty = true;
    showBanner("WAVE " + wave + " CLEARED   +250");
    playSfx("pickup", -6.0, 0.8, 0.85);
    intermission = 6.0;
    print("[tps] wave " + wave + " cleared, score=" + score);
    // resupply the plazas between waves
    var alive = 0;
    for (var p in pickups) {
      if (p.alive) {
        alive = alive + 1;
      }
    }
    if (alive < 4 && plazaPoints.length > 0) {
      var pt = plazaPoints[floor(frand() * plazaPoints.length) % plazaPoints.length];
      spawnPickup(frand() < 0.5 ? "health" : "ammo",
          pt[0] + frandRange(-2.0, 2.0), pt[1] + frandRange(-2.0, 2.0));
    }
  }
}

// ---------------------------------------------------------------------------
// game flow
// ---------------------------------------------------------------------------

void startGame() {
  // clear the previous run
  for (var f in foes) {
    if (f.body != null) {
      f.body.queueFree();
      f.body = null;
    }
  }
  foes = [];
  for (var p in pickups) {
    if (p.alive && p.node != null) {
      p.node.queueFree();
    }
  }
  pickups = [];

  hp = MAX_HP;
  lastDamageAt = -99.0;
  score = 0;
  kills = 0;
  shotsFired = 0;
  shotsHit = 0;
  wave = 0;
  pendingSpawns = 0;
  intermission = 2.5;
  reloading = 0.0;
  fireCooldown = 0.0;
  vignetteAlpha = 0.0;
  camShake = 0.0;
  weapons[0].mag = weapons[0].magSize;
  weapons[0].reserve = 120;
  weapons[1].mag = weapons[1].magSize;
  weapons[1].reserve = 24;
  setWeapon(0);

  // reset the player + camera
  px = 0.0;
  py = ROAD_Y;
  pz = 0.0;
  vx = 0.0;
  vy = 0.0;
  vz = 0.0;
  yaw = 0.0;
  pitch = -0.12;
  rigX = 0.0;
  rigY = ROAD_Y + EYE_HEIGHT;
  rigZ = 0.0;
  springCurrent = CAM_DIST;
  fovCurrent = FOV_BASE;
  GD.beginBatch();
  playerBody.set("position", Vector3(px, py, pz));
  playerBody.set("velocity", Vector3(0.0, 0.0, 0.0));
  camRig.set("position", Vector3(rigX, rigY, rigZ));
  camSpring.set("spring_length", GFloat(CAM_DIST));
  GD.endBatch();

  // pickups seeded on the plazas
  var seeded = 0;
  while (seeded < 4 && plazaPoints.length > 0) {
    var pt = plazaPoints[floor(frand() * plazaPoints.length) % plazaPoints.length];
    spawnPickup(seeded % 2 == 0 ? "health" : "ammo",
        pt[0] + frandRange(-2.0, 2.0), pt[1] + frandRange(-2.0, 2.0));
    seeded = seeded + 1;
  }

  menuLayer.set("visible", false);
  overLayer.set("visible", false);
  pauseLayer.set("visible", false);
  hud["layer"].set("visible", true);
  if (touchMode) {
    hud["touchLayer"].set("visible", true);
  } else {
    setMouseCaptured(true);
  }
  hudDirty = true;
  mode = "playing";
  showBanner("DEFEND THE DISTRICT");
  print("[tps] mission start");
}

void gameOver() {
  mode = "gameover";
  setMouseCaptured(false);
  var acc = 0;
  if (shotsFired > 0) {
    acc = (shotsHit * 100) ~/ shotsFired;
  }
  hud["overStats"].set("text",
      "waves survived: " + (wave - 1) + "\n" +
      "score: " + score + "    kills: " + kills + "\n" +
      "accuracy: " + acc + "%");
  overLayer.set("visible", true);
  playSfx("death", -3.0, 0.6, 0.65);
  print("[tps] mission failed â€” wave " + wave + " score=" + score +
      " kills=" + kills);
}

void togglePause() {
  if (mode == "playing") {
    mode = "paused";
    pauseLayer.set("visible", true);
    setMouseCaptured(false);
  } else if (mode == "paused") {
    mode = "playing";
    pauseLayer.set("visible", false);
    if (!touchMode) {
      setMouseCaptured(true);
    }
  }
}

void abandonToMenu() {
  if (mode != "paused") {
    return;
  }
  mode = "menu";
  pauseLayer.set("visible", false);
  hud["layer"].set("visible", false);
  if (touchMode) {
    hud["touchLayer"].set("visible", false);
  }
  menuLayer.set("visible", true);
}

// slow cinematic orbit over the city behind the menus
void menuVista(double delta) {
  menuYaw = menuYaw + delta * 0.07;
  GD.beginBatch();
  camRig.set("position", Vector3(0.0, 21.0, 0.0));
  camYawNode.set("rotation", Vector3(0.0, menuYaw, 0.0));
  camPitchNode.set("rotation", Vector3(-0.42, 0.0, 0.0));
  camSpring.set("spring_length", GFloat(36.0));
  camera.set("fov", GFloat(70.0));
  GD.endBatch();
}

void updateFps(double delta) {
  fpsTimer = fpsTimer - delta;
  if (fpsTimer > 0.0) {
    return;
  }
  fpsTimer = 1.0;
  if (engineSingleton is GObj) {
    var f = engineSingleton.call("get_frames_per_second", []);
    if (f is num) {
      hud["fps"].set("text", "" + floor(f) + " FPS");
    }
  }
}

// ---------------------------------------------------------------------------
// frame loop
// ---------------------------------------------------------------------------

void frame(double delta) {
  elapsed = elapsed + delta;
  if (mode == "playing") {
    pollDesktopInput();
    updatePlayer(delta);
    updateFoes(delta);
    updateWaves(delta);
    updatePickups(delta);
  } else if (mode == "menu" || mode == "gameover") {
    menuVista(delta);
  }
  updateEffects(delta);
  animateHud(delta);
  refreshHud();
  updateFps(delta);
  // one-shot intents are consumed every frame
  inJump = false;
  inReload = false;
}

// ---------------------------------------------------------------------------
// debug / test hooks (invoked from the host: tests, the editor, GDScript)
// ---------------------------------------------------------------------------

void tpsStartGame(args) {
  startGame();
}

void tpsDebugFire(args) {
  if (mode != "playing") {
    return;
  }
  fireCooldown = 0.0;
  reloading = 0.0;
  tryFire();
}

void tpsDebugHurt(args) {
  var amount = 25.0;
  if (args is List) {
    if (args.length > 0) {
      if (args[0] is num) {
        amount = args[0] * 1.0;
      }
    }
  }
  damagePlayer(amount);
}

void tpsDebugKillNearest(args) {
  var bestIx = -1;
  var bestDist = 99999.0;
  var i = 0;
  while (i < foes.length) {
    var f = foes[i];
    if (f.state != "dead") {
      var d = vlen3(f.x - px, 0.0, f.z - pz);
      if (d < bestDist) {
        bestDist = d;
        bestIx = i;
      }
    }
    i = i + 1;
  }
  if (bestIx >= 0) {
    var f = foes[bestIx];
    damageEnemy(bestIx, 100000.0, f.x, f.y + 1.0, f.z, false);
  }
}

void tpsDebugStatus(args) {
  print("[tps] status mode=" + mode + " wave=" + wave + " live=" +
      liveFoeCount() + " hp=" + floor(hp) + " score=" + score + " kills=" +
      kills + " ammo=" + weapons[currentWeapon].mag);
}

// ---------------------------------------------------------------------------
// main
// ---------------------------------------------------------------------------

void main() {
  print("[tps] boot: VICTOR CITY STRIKE on the Elpian VM");
  cacheConstants();
  inputSingleton = GD.input();
  engineSingleton = GD.engine();
  loadAssets();
  buildEnvironment();
  buildCity();
  buildAudio();
  buildEffects();
  buildPlayer();
  setupWeapons();
  buildHud();
  buildMenus();
  buildTouchControls();
  vpNode = GD.host().call("get_viewport", []);
  setupRaycast();

  mode = "menu";
  menuVista(0.0);

  GD.onProcess((delta) {
    frame(delta);
  });
  GD.onInput((event) {
    handleInput(event);
  });
  GD.onNotification((what) {
    // auto-pause when the app/browser tab loses focus
    if (mode == "playing") {
      if (what is num) {
        if (what != 0) {
          if (what == C["FOCUS_OUT"]) {
            togglePause();
          }
        }
      }
    }
  });

  print("[tps] ready â€” entering menu");
}
